// Handler registry. register(h) enforces the handler convention:
//   h.type is kebab-case (/^[a-z]+(-[a-z]+)*$/) AND typeof h.handle==='function'.
const TYPE_RE = /^[a-z]+(-[a-z]+)*$/;
const handlers = [];
function register(h) {
  if (!h || !TYPE_RE.test(h.type) || typeof h.handle !== "function") {
    throw new Error(`invalid handler: ${h && h.type}`);
  }
  handlers.push(h);
  return h;
}
function all() {
  return handlers;
}
module.exports = { register, all };
